SELECT students.student_id, students.name, programs.program_name
FROM students
JOIN programs ON students.program_id = programs.program_id;

SELECT AVG(enrollment_count) AS average_enrollments_per_student
FROM (
    SELECT student_id, COUNT(enrollment_id) AS enrollment_count
    FROM enrollments
    GROUP BY student_id
) AS enrollment_counts;

SELECT name
FROM students
WHERE program_id = 1;
